const response = $input.item.json;
const docInfo = $('Prepare Receipt Data').item.json;

try {
  // Step 1: Extract raw content
  let rawContent = response.choices?.[0]?.message?.content 
    || response.content 
    || response.output 
    || JSON.stringify(response);

  console.log('Raw content length:', rawContent.length);
  console.log('First 200 chars:', rawContent.substring(0, 200));

  if (!rawContent || rawContent.trim() === '') {
    throw new Error('Empty response from LLM');
  }

  // Step 2: Clean markdown formatting
  let cleaned = rawContent.trim()
    .replace(/^```json\s*/gi, '')
    .replace(/^```\s*/gi, '')
    .replace(/```\s*$/gi, '')
    .trim();

  // Step 3: Find JSON boundaries
  const firstBrace = cleaned.indexOf('{');
  const lastBrace = cleaned.lastIndexOf('}');

  if (firstBrace === -1 || lastBrace === -1) {
    console.error('No JSON braces found in:', cleaned.substring(0, 500));
    throw new Error('No valid JSON structure found');
  }

  cleaned = cleaned.slice(firstBrace, lastBrace + 1);
  console.log('Extracted JSON length:', cleaned.length);

  // Step 4: Fix common JSON issues
  cleaned = cleaned
    // Fix dollar amounts
    .replace(/:\s*"\$?([\d,]+\.?\d*)"/g, (match, num) => {
      const fixed = parseFloat(num.replace(/,/g, ''));
      return ': ' + (isNaN(fixed) ? 0 : fixed);
    })
    // Fix unquoted dollar amounts
    .replace(/:\s*\$?([\d,]+\.?\d*)\s*([,}\]])/g, (match, num, ending) => {
      const fixed = parseFloat(num.replace(/,/g, ''));
      return ': ' + (isNaN(fixed) ? 0 : fixed) + ending;
    })
    // Fix NaN, Infinity, undefined
    .replace(/:\s*NaN\s*([,}\]])/g, ': 0$1')
    .replace(/:\s*Infinity\s*([,}\]])/g, ': 0$1')
    .replace(/:\s*undefined\s*([,}\]])/g, ': null$1')
    // Fix trailing commas
    .replace(/,(\s*[}\]])/g, '$1')
    // Fix duplicate commas
    .replace(/,\s*,/g, ',')
    // Fix missing commas between fields
    .replace(/"\s*"([a-zA-Z_])/g, '", "$1')
    // Fix single quotes to double quotes
    .replace(/'/g, '"')
    // Fix newlines in strings (if any)
    .replace(/\n/g, ' ');

  console.log('Cleaned JSON (first 300 chars):', cleaned.substring(0, 300));
  console.log('Around position 1380:', cleaned.substring(1350, 1420));

  // Step 5: Parse JSON
  let receiptData;
  try {
    receiptData = JSON.parse(cleaned);
  } catch (parseError) {
    console.error('JSON Parse Error:', parseError.message);
    console.error('Position:', parseError.message.match(/position (\d+)/)?.[1]);

    // Show context around error
    const errorPos = parseInt(parseError.message.match(/position (\d+)/)?.[1] || 0);
    if (errorPos > 0) {
      console.error('Context around error:', cleaned.substring(Math.max(0, errorPos - 50), errorPos + 50));
    }

    throw new Error(`JSON parsing failed: ${parseError.message}`);
  }

  // Step 6: Validate required fields
  if (!receiptData) {
    throw new Error('Receipt data is null after parsing');
  }

  console.log('✓ Receipt parsed successfully');
  console.log('Merchant:', receiptData.merchant_name);
  console.log('Total:', receiptData.total_amount);
  console.log('Items count:', receiptData.items?.length || 0);

  // Step 7: Return structured data
  return {
    json: {
      document_id: docInfo.document_id,
      user_id: docInfo.user_id,
      file_name: docInfo.file_name,
      receipt_data: receiptData
    }
  };

} catch (error) {
  console.error('❌ Receipt parsing failed:', error.message);
  console.error('Error stack:', error.stack);

  // Return error info for debugging
  throw new Error(`Receipt parsing error: ${error.message}. Check execution logs for details.`);
}

const response = $input.item.json;
const receiptInfo = $('Parse Receipt Response').item.json;

let validation = null;
try {
  let rawContent = response.choices?.[0]?.message?.content || response.content;
  let cleaned = rawContent.trim().replace(/^```json\s*/i, '').replace(/```$/i, '');
  const firstBrace = cleaned.indexOf('{');
  const lastBrace = cleaned.lastIndexOf('}');
  cleaned = cleaned.slice(firstBrace, lastBrace + 1);
  validation = JSON.parse(cleaned);
} catch (error) {
  validation = {
    validation_score: 70,
    status: 'needs_review',
    is_business_expense: null,
    reimbursable: null,
    tax_deductible: null,
    issues: []
  };
}

return {
  json: {
    document_id: receiptInfo.document_id,
    user_id: receiptInfo.user_id,
    receipt_data: receiptInfo.receipt_data,
    validation: validation
  }
};

const data = $input.item.json;
const receipt = data.receipt_data;
const validation = data.validation;

const payload = {
  document_id: data.document_id,
  processed_data: {
    merchant_name: receipt.merchant_name,
    total_amount: receipt.total_amount,
    currency: receipt.currency || 'USD',
    purchase_date: receipt.purchase_date,
    category: receipt.expense_category,
    tax_amount: receipt.tax_amount || 0,
    payment_method: receipt.payment_method || 'unknown',
    is_business_expense: validation.is_business_expense ?? receipt.is_business_expense,
    items: receipt.items || []
  },
  validation: {
    confidence_score: validation.validation_score,
    status: validation.status || 'needs_review',
    errors: validation.issues || []
  },
  timestamp: new Date().toISOString()
};

console.log('Receipt webhook:', payload.processed_data.merchant_name, payload.processed_data.total_amount);

return { json: payload };

